function elementSummary(character) {
  return elementLabel(character);
}

function elementLabel(character) {
  return elementById(majorityElement(character)).label;
}

function elementMixSummary(character) {
  const entries = character.elements && character.elements.length ? character.elements : [{ name: character.element, percent: "100" }];
  return entries.map((entry) => {
    const element = elementById(entry.name);
    return entry.percent ? `${element.label} ${entry.percent}%` : element.label;
  }).join(" / ");
}

function majorityElement(character) {
  const entries = character.elements && character.elements.length ? character.elements : [{ name: character.element, percent: "100" }];
  return entries.reduce((best, entry) => {
    const value = Number.parseFloat(entry.percent) || 0;
    return value > best.value ? { name: entry.name, value } : best;
  }, { name: character.element || "physical", value: -1 }).name;
}

function patchSelectOptions() {
  return [
    `<option value="">No release patch set</option>`,
    ...(db.gamePatches || [])
      .slice()
      .sort((a, b) => patchNumber(a) - patchNumber(b))
      .map((patch) => `<option value="${escapeAttribute(patch.id)}">${escapeHtml(displayText(patch.name))}</option>`)
  ].join("");
}

function releasePatchName(value) {
  const patch = (db.gamePatches || []).find((item) => item.id === value || item.name === value);
  return patch?.name || value || "";
}

function renderElementMix(character) {
  const entries = character.elements && character.elements.length ? character.elements : [{ name: character.element, percent: "100" }];
  return entries.map((entry) => {
    const element = elementById(entry.name);
    const percent = Number.parseFloat(entry.percent) || 0;
    return `
      <span class="element-bar" style="--accent:${element.color}; --value:${Math.max(0, Math.min(100, percent))}%">
        <strong>${element.label}</strong>
        <span>${entry.percent || "?"}%</span>
      </span>
    `;
  }).join("");
}

function displayText(value = "") {
  return String(value)
    .replace(/â˜…/g, "★")
    .replace(/â€”/g, "-")
    .replace(/â€“/g, "-")
    .replace(/â€™/g, "'")
    .replace(/â€œ|â€/g, '"');
}

function escapeHtml(value = "") {
  return String(value).replace(/[&<>"']/g, (char) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    "\"": "&quot;",
    "'": "&#39;"
  }[char]));
}

function escapeAttribute(value = "") {
  return escapeHtml(value);
}

function richText(value = "") {
  const template = document.createElement("template");
  template.innerHTML = expandRichTextShortcodes(displayText(value));
  sanitizeRichNode(template.content);
  return template.innerHTML;
}

function expandRichTextShortcodes(value = "") {
  let output = String(value || "");
  const colorMap = {
    red: "#F16549",
    orange: "#F16549",
    blue: "#3168B9",
    default: "inherit"
  };
  output = output.replace(/\[(red|orange|blue|default)\]([\s\S]*?)\[\/\1\]/gi, (_, colorKey, content) => {
    const color = colorMap[colorKey.toLowerCase()] || "inherit";
    return `<span style="color:${color}">${content}</span>`;
  });
  output = output.replace(/\[\[(weapon|memory|character|construct|cub|item):([^\]|]+)(?:\|([^\]]+))?\]\]/gi, (_, type, rawTarget, rawLabel) => {
    const link = richEntityLink(type, rawTarget, rawLabel);
    return link || rawLabel || rawTarget;
  });
  return output;
}

function richEntityLink(type, rawTarget, rawLabel) {
  const target = displayText(rawTarget).trim();
  const label = displayText(rawLabel || rawTarget).trim();
  const entity = linkedEntity(type, target);
  if (!entity) return "";
  return `<a href="${escapeAttribute(entity.href)}" class="entity-link" title="${escapeAttribute(entity.title)}">${escapeHtml(label || entity.label)}</a>`;
}

function linkedEntity(type, target) {
  const normalizedType = String(type || "").toLowerCase();
  const key = String(target || "").trim().toLowerCase();
  const findByIdOrName = (items = []) => items.find((item) =>
    String(item.id || "").toLowerCase() === key ||
    String(item.name || item.title || "").toLowerCase() === key ||
    slugify(item.name || item.title || "") === slugify(target)
  );
  if (normalizedType === "weapon") {
    const weapon = findByIdOrName(db.weapons || []);
    return weapon ? { href: "#weapons", label: weapon.name, title: `Weapon: ${weapon.name}` } : null;
  }
  if (normalizedType === "memory") {
    const memory = findByIdOrName(db.memories || []);
    return memory ? { href: "#memories", label: memory.name, title: `Memory: ${memory.name}` } : null;
  }
  if (normalizedType === "cub") {
    const cub = findByIdOrName(db.cubs || []);
    return cub ? { href: "#cubs", label: cub.name, title: `CUB: ${cub.name}` } : null;
  }
  if (normalizedType === "item") {
    const item = findByIdOrName(db.items || []);
    return item ? { href: "#items", label: item.name, title: `Item: ${item.name}` } : null;
  }
  if (normalizedType === "character" || normalizedType === "construct") {
    const character = findByIdOrName(db.characters || []);
    return character ? { href: `#construct/${character.id}/kit`, label: character.name, title: `Construct: ${character.name}` } : null;
  }
  return null;
}

function sanitizeRichNode(root) {
  const allowedTags = new Set(["A", "B", "BR", "CODE", "EM", "I", "LI", "OL", "P", "S", "SMALL", "SPAN", "STRONG", "SUB", "SUP", "U", "UL"]);
  const allowedClasses = new Set(["entity-link"]);
  const allowedStyles = new Set(["color", "background-color", "font-family", "font-size"]);
  root.querySelectorAll("*").forEach((node) => {
    if (!allowedTags.has(node.tagName)) {
      node.replaceWith(document.createTextNode(node.textContent || ""));
      return;
    }
    [...node.attributes].forEach((attr) => {
      const name = attr.name.toLowerCase();
      if (node.tagName === "A" && name === "href") {
        const href = attr.value.trim();
        if (/^(https?:|mailto:|#|\/)/i.test(href)) {
          if (!href.startsWith("#")) {
            node.setAttribute("target", "_blank");
            node.setAttribute("rel", "noreferrer");
          }
          return;
        }
      }
      if (name === "title") return;
      if (name === "class") {
        const safeClasses = attr.value.split(/\s+/).filter((className) => allowedClasses.has(className));
        if (safeClasses.length) {
          node.setAttribute("class", safeClasses.join(" "));
          return;
        }
      }
      if (name === "style") {
        const safeStyle = attr.value.split(";").map((rule) => rule.trim()).filter((rule) => {
          const [property, rawValue = ""] = rule.split(":").map((part) => part.trim().toLowerCase());
          return allowedStyles.has(property) && !/url|expression|javascript/i.test(rawValue);
        }).join("; ");
        if (safeStyle) {
          node.setAttribute("style", safeStyle);
          return;
        }
      }
      node.removeAttribute(attr.name);
    });
  });
}

init();

